/* BIM AI design tokens — dark chrome overrides.
 *
 * Source of truth: spec/ui-ux-redesign-v1-spec.md §9 (dark column).
 * Activated by `<html data-theme="dark">` or `<html class="dark">`.
 */

:root[data-theme='dark'],
:root.dark {
  /* §9.1 Color — semantic chrome (dark) */
  --color-background: hsl(220 14% 10%);
  --color-foreground: hsl(220 14% 92%);
  --color-surface: hsl(220 12% 13%);
